mapper.insert:
insert into TBL_ROLE (ROLE_ID, ROLE_NAME, IS_AVAILABLE, 
  CREATE_TIME, CREATE_BY, UPDATE_TIME, 
  UPDATE_BY, RESERVED_FIELD1, RESERVED_FIELD2, 
  RESERVED_FIELD3, WEIGHT, ORG
  )
values (#{roleId,jdbcType=VARCHAR}, #{roleName,jdbcType=VARCHAR}, #{isAvailable,jdbcType=VARCHAR}, 
  #{createTime,jdbcType=TIMESTAMP}, #{createBy,jdbcType=VARCHAR}, #{updateTime,jdbcType=TIMESTAMP}, 
  #{updateBy,jdbcType=VARCHAR}, #{reservedField1,jdbcType=VARCHAR}, #{reservedField2,jdbcType=VARCHAR}, 
  #{reservedField3,jdbcType=VARCHAR}, #{weight,jdbcType=VARCHAR}, #{org,jdbcType=VARCHAR}
  )

mapper.select:
select

from TBL_ROLE a where 1=1
and (cast(a.WEIGHT as bigint) < (select cast(re.WEIGHT as bigint) from  tbl_role re,tbl_user ur where re.role_id=ur.role_id  and USER_ID = ${roleReqParam.userId}))


    and ROLE_ID = ${roleReqParam.roleId}


    and ROLE_NAME like  '%${roleReqParam.roleName}%'


    and IS_AVAILABLE  =  #{roleReqParam.isAvailable}


    and ORG  =  #{roleReqParam.org}

mapper.update:
update TBL_ROLE
set IS_AVAILABLE = #{isAvailable,jdbcType=VARCHAR}
where ROLE_ID = #{roleId,jdbcType=VARCHAR}
